def solve(nums):
  dp = [0] * len(nums)
  dp[0], dp[1] = nums[0], max(nums[0], nums[1])
  for i in range(2, len(nums)):
    dp[i] = max(dp[i-1], dp[i-2] + nums[i])
  return dp[-1]
class Solution:
  def rob(self, nums: list[int]) -> int:
    return solve(nums)

