#include <iostream>
#include <vector>
using namespace std;
class Solution {
 public:
  int rob(vector<int>& nums) {
    vector<int> dp(nums.size(), 0);
    dp[0] = nums[0];
    dp[1] = max(nums[0], nums[1]);
    for (int i = 2; i < nums.size(); i++)
      dp[i] = max(dp[i-1], dp[i-2] + nums[i]);
    return dp.back();
  }
};

int main() {
  int n;
  cin >> n;
  vector<int> nums(n);
  for (int i = 0; i < n; i++)
    cin >> nums[i];
  Solution s;
  cout << s.rob(nums) << endl;
  return 0;
}
